import{_ as t,o,c as e,a0 as r}from"./chunks/framework.Bogozrur.js";const c=JSON.parse('{"title":"朝鉴 · 荆州早报","description":"","frontmatter":{"title":"2026-06-02T00:00:00.000Z","date":"2026-06-02T00:00:00.000Z","categories":["chaojian"],"tags":["朝鉴","趋势洞察","新闻","经济"],"author":"银枢局"},"headers":[],"relativePath":"posts/chaojian/chaojian-2026-06-02.md","filePath":"posts/chaojian/chaojian-2026-06-02.md"}'),h={name:"posts/chaojian/chaojian-2026-06-02.md"};function i(l,a,n,u,q,s){return o(),e("div",null,[...a[0]||(a[0]=[r('<h1 id="朝鉴-·-荆州早报" tabindex="-1">朝鉴 · 荆州早报 <a class="header-anchor" href="#朝鉴-·-荆州早报" aria-label="Permalink to &quot;朝鉴 · 荆州早报&quot;">​</a></h1><p><strong>2026年6月2日 星期二 | 农历四月十七</strong></p><hr><h2 id="☀️-今日天气" tabindex="-1">☀️ 今日天气 <a class="header-anchor" href="#☀️-今日天气" aria-label="Permalink to &quot;☀️ 今日天气&quot;">​</a></h2><p><strong>多云转中雨 | 24~30℃ | 西南风微风 | 湿度73%</strong></p><p>空气优 | 感冒极易发 | 洗车不适宜 | 出门带伞</p><hr><h2 id="📰-荆州十大热点" tabindex="-1">📰 荆州十大热点 <a class="header-anchor" href="#📰-荆州十大热点" aria-label="Permalink to &quot;📰 荆州十大热点&quot;">​</a></h2><h3 id="_1️⃣-荆州获中央10亿元财政支持-入选国家城市更新行动示范城市" tabindex="-1">1️⃣ 荆州获中央10亿元财政支持，入选国家城市更新行动示范城市 <a class="header-anchor" href="#_1️⃣-荆州获中央10亿元财政支持-入选国家城市更新行动示范城市" aria-label="Permalink to &quot;1️⃣ 荆州获中央10亿元财政支持，入选国家城市更新行动示范城市&quot;">​</a></h3><p>财政部发布2026年度中央财政支持实施城市更新行动评选结果，荆州成功入选全国15个示范城市之一，将获得中部地区最高10亿元定额补助。荆州采用&quot;绣花&quot;&quot;织补&quot;方式推进5条历史文化街区微改造，沙市码头历史文化街区已入选住建部可复制经验清单。</p><h3 id="_2️⃣-荆州终止防汛四级应急响应" tabindex="-1">2️⃣ 荆州终止防汛四级应急响应 <a class="header-anchor" href="#_2️⃣-荆州终止防汛四级应急响应" aria-label="Permalink to &quot;2️⃣ 荆州终止防汛四级应急响应&quot;">​</a></h3><p>5月31日，荆州市防汛抗旱指挥部办公室发布通知，终止防汛四级应急响应。长湖水位32.11米，已稳定在警戒水位以下并呈下降趋势，全市江河湖库水情趋于平稳并继续回落。此前受强降雨影响，荆州部分河湖沟渠水位持续上涨，各级工会深入一线慰问防汛人员。</p><h3 id="_3️⃣-高考在即-荆州4-2万人报名-多路段实施交通管制" tabindex="-1">3️⃣ 高考在即！荆州4.2万人报名，多路段实施交通管制 <a class="header-anchor" href="#_3️⃣-高考在即-荆州4-2万人报名-多路段实施交通管制" aria-label="Permalink to &quot;3️⃣ 高考在即！荆州4.2万人报名，多路段实施交通管制&quot;">​</a></h3><p>2026年全市高考报名4.2万人，小语种报名2614人。6月7日-9日考试期间，荆州中学、江陵中学、北门中学等考点周边道路将实施临时交通管制，听力考试期间部分路段禁止车辆通行。</p><h3 id="_4️⃣-荆州全面开通中高考考生身份证-绿色通道" tabindex="-1">4️⃣ 荆州全面开通中高考考生身份证&quot;绿色通道&quot; <a class="header-anchor" href="#_4️⃣-荆州全面开通中高考考生身份证-绿色通道" aria-label="Permalink to &quot;4️⃣ 荆州全面开通中高考考生身份证&quot;绿色通道&quot;&quot;">​</a></h3><p>针对考生身份证到期或临时丢失等情况，荆州市公安局即日起至6月23日全面开通考生办理居民身份证&quot;绿色通道&quot;，保证考生用证需求。</p><h3 id="_5️⃣-湖北省青少年排球锦标赛-甲组-在荆州开赛" tabindex="-1">5️⃣ 湖北省青少年排球锦标赛（甲组）在荆州开赛 <a class="header-anchor" href="#_5️⃣-湖北省青少年排球锦标赛-甲组-在荆州开赛" aria-label="Permalink to &quot;5️⃣ 湖北省青少年排球锦标赛（甲组）在荆州开赛&quot;">​</a></h3><p>5月27日至6月3日，2026年湖北省青少年排球锦标赛（甲组）在荆州文体中心体育馆燃情开赛，赛事由湖北省体育局主办，荆州市体育局承办。</p><h3 id="_6️⃣-荆州老街蝶变-活化红色历史-革命老街火出圈" tabindex="-1">6️⃣ 荆州老街蝶变：活化红色历史，革命老街火出圈 <a class="header-anchor" href="#_6️⃣-荆州老街蝶变-活化红色历史-革命老街火出圈" aria-label="Permalink to &quot;6️⃣ 荆州老街蝶变：活化红色历史，革命老街火出圈&quot;">​</a></h3><p>荆州注重整体保护和活态传承有机结合，21处革命旧址展陈全面焕新，洪湖赤卫队纪念馆首度开放，国内首创水上实景战役《这一仗打得真漂亮》融合水幕投影、爆破特效还原革命烽火，将线上&quot;流量&quot;转化为线下&quot;增量&quot;。</p><h3 id="_7️⃣-多彩活动庆-六一-荆州萌娃欢乐过节" tabindex="-1">7️⃣ 多彩活动庆&quot;六一&quot;，荆州萌娃欢乐过节 <a class="header-anchor" href="#_7️⃣-多彩活动庆-六一-荆州萌娃欢乐过节" aria-label="Permalink to &quot;7️⃣ 多彩活动庆&quot;六一&quot;，荆州萌娃欢乐过节&quot;">​</a></h3><p>6月1日国际儿童节，荆州各地开展形式多样的庆六一活动。荆州市实验幼儿园举办&quot;小创客·小健将·小艺术家&quot;六一&quot;三栖&quot;嘉年华，孩子们在小实验中感受科学魅力。</p><h3 id="_8️⃣-荆州市2026年高中阶段学校招生方案公布" tabindex="-1">8️⃣ 荆州市2026年高中阶段学校招生方案公布 <a class="header-anchor" href="#_8️⃣-荆州市2026年高中阶段学校招生方案公布" aria-label="Permalink to &quot;8️⃣ 荆州市2026年高中阶段学校招生方案公布&quot;">​</a></h3><p>荆州市教育局发布2026年招生方案，省级重点高中荆州中学面向荆州区、江陵县、松滋市、公安县、石首市、监利市和洪湖市招生；沙市中学面向沙市区（含经开区）及周边县市招生，实行属地招生原则。</p><h3 id="_9️⃣-青创荆州-第三届青年创新创业大赛决赛圆满落幕" tabindex="-1">9️⃣ &quot;青创荆州&quot;第三届青年创新创业大赛决赛圆满落幕 <a class="header-anchor" href="#_9️⃣-青创荆州-第三届青年创新创业大赛决赛圆满落幕" aria-label="Permalink to &quot;9️⃣ &quot;青创荆州&quot;第三届青年创新创业大赛决赛圆满落幕&quot;">​</a></h3><p>5月28日，荆岳区域党建合作共建暨2026年&quot;青创荆州&quot;第三届青年创新创业大赛决赛在石首落幕，鄂湘两省1600余名青年创客同台角逐。</p><h3 id="🔟-荆州市未成年人关爱保护宣传周活动启动" tabindex="-1">🔟 荆州市未成年人关爱保护宣传周活动启动 <a class="header-anchor" href="#🔟-荆州市未成年人关爱保护宣传周活动启动" aria-label="Permalink to &quot;🔟 荆州市未成年人关爱保护宣传周活动启动&quot;">​</a></h3><p>&quot;同心护未来&quot;2026年荆州市未成年人关爱保护宣传周活动在沙市区洪垸社区启动，市民政局牵头，联动检察院、团市委、公安局、未保中心及爱心企业，护航未成年人健康成长。</p><hr><h2 id="📌-温馨提示" tabindex="-1">📌 温馨提示 <a class="header-anchor" href="#📌-温馨提示" aria-label="Permalink to &quot;📌 温馨提示&quot;">​</a></h2><ul><li>🌧️ 今夜转中雨，明日持续降雨，外出请携带雨具</li><li>🎓 高考倒计时5天，考点周边将陆续实施交通管制</li><li>🚗 洗车不适宜，降雨天气注意行车安全</li><li>💡 荆州智慧制造产业园预计本月交付，可吸纳约30家企业入驻</li></ul><hr>',32)])])}const p=t(h,[["render",i]]);export{c as __pageData,p as default};
